var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"일단 대본을 받긴 했는데, 아무리 리허설이라도 무대에 서려니까 긴장되네.","JPN":"とりあえず台本はもらったけど、急に舞台に立つって考えたら\\n緊張してくるね。","ENG":"I got the script, but I'm getting nervous about going up on stage for the rehearsal.","TWN":"雖然是有拿到劇本，但畢竟是要上台，還是有點緊張呢。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"신호가 왔어, 이제 무대로 나가면 되나?","JPN":"合図だ。もう舞台に上がればいいのかな？","ENG":"That's my cue. Do I go up on stage now?","TWN":"打Pass了，現在出場嗎？"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"줄리엣! 내, 내가 돌아왔다네. 그동안 잘 지냈나?","JPN":"ジュリエット！　ぼ、僕が帰ってきた。元気だったか？","ENG":"Juliet! I-it is my lady, O, it is my love!","TWN":"茱麗葉！我，我回來了，你過得好嗎？"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"로미오, 이렇게 다시 만나서 정말로 기쁘군요.","JPN":"ロミオ、こうして再びお会いできて本当に嬉しいです。","ENG":"O, Romeo, how camest thou hither, tell me, and wherefore?","TWN":"羅密歐，我好開心還能再見到你。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"어라, 회장? 여기서는…….","JPN":"あれ、会長？　ここは……","ENG":"Y-Yen? That's not the next line...","TWN":"嗯？會長？這裡要……"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"정말로 기쁘군요, 로미오. 이렇게 제 앞에 다시 모습을 드러내시다니!","JPN":"ああ、心から嬉しいです、ロミオ。\\nこのように私の前に再び姿を現すなんて！","ENG":"By whose direction found’st thou out this place?","TWN":"羅密歐，我好開心，你竟然敢再次出現在我面前！"},"stage":{"bg":"HALL","slots":{"L":null,"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"우, 우왓! 무슨 짓이야!","JPN":"うわっ！　何してるの！？","ENG":"W-whoa! What are you doing?!","TWN":"哇啊！你幹嘛！"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"무슨 말씀이시죠? 이 저택에 발을 들였을 때부터 목숨을 버릴 각오는 하셨을 텐데요?","JPN":"何のことでしょう？　この邸宅に再び足を踏み入れたということは、\\n命を捨てる覚悟をなさったのでは？","ENG":"And the place death, considering who thou art.","TWN":"什麼幹嘛？當你踏入這棟房子時，應該就已經做好赴死的心理準備吧？"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐라고? 내가 받은 대본에서는……!","JPN":"ええ？　私の台本にはそんな……！","ENG":"What? That's not in my script...!","TWN":"赴死？可是我收到的劇本……！"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"못 본 사이에 잡담이 느셨군요. 유언은 그게 전부인가요?","JPN":"見ない間に饒舌な方になりましたね。遺言はそれだけでしょうか？","ENG":"Thou pratest far too much, dost thou not see? Are those thy parting words, thy final plea?","TWN":"這麼久不見，你的話變多了呢。這就是你最後的遺言嗎？"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아니! 처음부터 명백한 NG잖아! 연극부 애들은 대체 뭘 하고 있는 거야?","JPN":"いやいやいや！　これは明らかにNGでしょ！\\n演劇部は何してるの？","ENG":"No! This was obviously wrong from the start! What the heck is the theater club doing?!","TWN":"拜託！剛才不是已經NG了嗎！戲劇部的人怎麼都不喊卡？"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐라고!? 애드리브로 진행하라고!? 그게 무슨!?","JPN":"は？　アドリブで続けろって！？　どういうこと！？","ENG":"WHAT?! You want me to improvise the whole thing?!","TWN":"什麼！？要我即興發揮！？胡說八道什麼！？"},"stage":{"bg":"GRONIA_HALL","slots":{"L":{"char_id":"ACTING_NPC_GEASS_CHIEF","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ACTING_NPC_GEASS_STAFF","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"서운하군요, 로미오. 절 두고 어딜 보시는 거죠?","JPN":"寂しいですわ、ロミオ。\\n私を放っておいて、どこに目を向けているのですか？","ENG":"O, Romeo, wilt thou leave me so unsatisfied?","TWN":"真令人難過。羅密歐，你為何轉頭不看我呢？"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"좋아. 이렇게 된 이상…… 나도 내 마음대로 애드리브 해주겠어!","JPN":"よし、こうなった以上……私も勝手にアドリブでやっていくからね！","ENG":"All right. If this is what you want... I'll make my own lines too!","TWN":"好吧，既然如此……那我也要來即興發揮囉！"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ACTING_NPC_GEASS_STAFF","text":{"KOREA":"진심이에요 부장? 저 둘에게 각각 다른 대본을 줬다고요!?","JPN":"本気ですか、部長？　二人にそれぞれ違う台本を渡したんですか？","ENG":"You can't be serious! You gave them different scripts on purpose?!","TWN":"社長，你是說真的嗎？她們二個人拿到的是不同的劇本嗎？"},"stage":{"bg":"GRONIA_HALL","slots":{"L":{"char_id":"ACTING_NPC_GEASS_CHIEF","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ACTING_NPC_GEASS_STAFF","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"ACTING_NPC_GEASS_CHIEF","text":{"KOREA":"아까 뭘 들었어? 화려한 연출만 보여줄 수 있다면, 스토리 같은 건 아무래도 좋다구.","JPN":"さっきの話を聞いてないの？\\n華やかな演出さえ見せられるなら、ストーリーなんてどうでもいいのよ。","ENG":"Didn't you hear what I said? If we can put on a brilliant performance, the story doesn't matter at all!","TWN":"我剛怎麼說的？只要有華麗的大場面，劇情怎麼樣根本無所謂。"},"stage":{"bg":"GRONIA_HALL","slots":{"L":{"char_id":"ACTING_NPC_GEASS_CHIEF","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ACTING_NPC_GEASS_STAFF","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"ACTING_NPC_GEASS_CHIEF","text":{"KOREA":"저길 봐, 두 사람 다 대본 같은 게 없어도 알아서 연기에 몰두하고 있잖아?","JPN":"あれを見なさい。\\n二人とも台本なんか無くても演技に没頭しているじゃない？","ENG":"Look! Those two are in character despite getting completely different scripts!","TWN":"你們看，她們二個就算沒有劇本，也可以投入在演出中不是嗎？"},"stage":{"bg":"GRONIA_HALL","slots":{"L":{"char_id":"ACTING_NPC_GEASS_CHIEF","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ACTING_NPC_GEASS_STAFF","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"ACTING_NPC_GEASS_STAFF","text":{"KOREA":"어…… 저걸 연기라고 하기에는…….","JPN":"えーと……あれを演技というには……","ENG":"Uh... But can you really call that acting...?","TWN":"呃……那算是演出嗎……"},"stage":{"bg":"GRONIA_HALL","slots":{"L":{"char_id":"ACTING_NPC_GEASS_CHIEF","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ACTING_NPC_GEASS_STAFF","face":"UNIT_DESPAIR"}}}},{"id":"L36_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"진정해, 회장! 왜 그렇게 진지한 거야? 이건 그냥 리허설일 뿐이잖아!","JPN":"落ち着いて、会長！　どうしてそこまで真剣にやるの！？\\nただのリハーサルでしょ！","ENG":"Yen, calm down! Why are you so committed to this? It's just a rehearsal!","TWN":"會長，你冷靜點！你這麼認真幹嘛？這只是彩排而已欸！"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};